<script setup lang="ts">import {Download,Plus,View} from '@element-plus/icons-vue';import {onMounted,reactive,ref} from 'vue';import {api} from '@/api/client';const rows=ref<any[]>([]),preview=ref(''),dialog=ref(false),form=reactive({week:'2025-W29',cities:'shanghai'});async function load(){rows.value=(await api.reports()).data.data}async function generate(){await api.generateReport({week:form.week,cities:form.cities.split(',')});load()}async function show(id:number){preview.value=(await api.report(id)).data.data.content;dialog.value=true}function download(id:number,format:string){window.open(`${import.meta.env.VITE_API_BASE_URL}/reports/${id}/download?format=${format}`,'_blank')}onMounted(load)</script>
<template><ElCard shadow="never"><div class="toolbar"><ElInput v-model="form.week" placeholder="周次"/><ElInput v-model="form.cities" placeholder="城市代码"/><ElButton type="primary" :icon="Plus" @click="generate">生成周报</ElButton></div><ElTable :data="rows"><ElTableColumn prop="week" label="周次"/><ElTableColumn prop="cities" label="城市"/><ElTableColumn prop="activity_count" label="活动数"/><ElTableColumn prop="status" label="状态"/><ElTableColumn label="操作"><template #default="s"><ElButton text :icon="View" @click="show(s.row.id)">预览</ElButton><ElButton text :icon="Download" @click="download(s.row.id,'md')">Markdown</ElButton><ElButton text :icon="Download" @click="download(s.row.id,'xlsx')">Excel</ElButton></template></ElTableColumn></ElTable></ElCard><ElDialog v-model="dialog" title="周报预览" width="760"><div class="report-preview">{{preview}}</div></ElDialog></template>
